ee:message.ee:set-payload:
%dw 2.0
output application/json
var javaTests = java!com::mycompany::perf::LoadRunner::list()
---
{
    tests: javaTests map (test) -> {
        id: test.id,
        status: test.status,
        targetUrl: test.targetUrl,
        method: test.method,
        concurrency: test.concurrency,
        totalRequests: test.totalRequests default 0
    },
    count: sizeOf(javaTests)
}

%dw 2.0
output application/json
var metrics = java!com::mycompany::perf::LoadRunner::status(vars.testId)
---
if (metrics != null) metrics
else {error: "Not Found", message: "Test " ++ (vars.testId default "") ++ " not found"}

%dw 2.0
output application/json
var result = java!com::mycompany::perf::LoadRunner::stop(vars.testId)
---
{
    id: vars.testId,
    stopped: result.stopped,
    status: if (result.stopped) "stopped" else "not_found",
    message: if (result.stopped) "Test stopped" else "Test not found"
}
